extends Node

signal coin_changed(new_count: int)

var _count: int = 0
var _save_path: String = "user://save.json"

func _ready() -> void:
	load_count()
	get_tree().root.size = Vector2i(640, 480)

func _notification(what: int) -> void:
	if what == NOTIFICATION_WM_CLOSE_REQUEST:
		save_count()

func add_coin() -> void:
	_count += 1
	coin_changed.emit(_count)

func get_count() -> int:
	return _count

func save_count() -> void:
	var file = FileAccess.open(_save_path, FileAccess.WRITE)
	if file:
		var data = {"count": _count}
		file.store_string(JSON.stringify(data))
		file.close()

func load_count() -> void:
	if not FileAccess.file_exists(_save_path):
		return
	var file = FileAccess.open(_save_path, FileAccess.READ)
	if file:
		var content = file.get_as_text()
		file.close()
		var json = JSON.new()
		var error = json.parse(content)
		if error == OK:
			var data = json.get_data()
			if data != null and data.has("count"):
				_count = int(data["count"])
				coin_changed.emit(_count)

extends CharacterBody2D

const SPEED: float = 300.0


func _physics_process(delta: float) -> void:
	var direction := Vector2(
		Input.get_axis("ui_left", "ui_right"),
		Input.get_axis("ui_up", "ui_down")
	)
	velocity = direction * SPEED
	move_and_slide()

extends CanvasLayer


func _ready() -> void:
	_update_label(Inventory.get_count())
	Inventory.coin_changed.connect(_on_coin_changed)


func _on_coin_changed(new_count: int) -> void:
	_update_label(new_count)


func _update_label(count: int) -> void:
	$Label.text = "Coins: %d" % count

